10→// TestContractMatrix_Baseline validates all contract cases against
11→// ValidateRequest directly. This is the ground-truth reference that
12→// per-entry-point runners (handler, mcp) must agree with.
13→func TestContractMatrix_Baseline(t *testing.T) {
14→	t.Parallel()
15→	defaultReg := search.NewRegistry()
16→
17→	for _, cc := range search.ContractCases() {
18→		t.Run(cc.Name, func(t *testing.T) {
19→			t.Parallel()
20→
21→			reg := defaultReg
22→			if cc.Registry != nil {
23→				reg = cc.Registry
24→			}
25→
26→			errs := search.ValidateRequest(reg, cc.Request, cc.Authenticated)
27→
28→			if cc.WantValid {
29→				if len(errs) != 0 {
30→					t.Fatalf("expected valid request, got %d errors: %+v", len(errs), errs)
31→				}
32→				return
33→			}
34→
35→			// Expect at least one error matching the contract.
36→			if len(errs) == 0 {
37→				t.Fatal("expected validation errors, got none")
38→			}
39→
40→			found := false
41→			for _, e := range errs {
42→				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
43→					found = true
44→					break
45→				}
46→			}
47→			if !found {
48→				t.Errorf("expected error field=%q containing %q, got: %+v",
49→					cc.WantField, cc.WantContains, errs)
50→			}
51→		})
52→	}
53→}
