 17→// TestContractMatrix_Export runs the shared contract cases through the CSV
 18→// export handler, verifying that the export adapter produces the same
 19→// validation outcomes as the baseline.
 20→func TestContractMatrix_Export(t *testing.T) {
 21→	t.Parallel()
 22→	defaultReg := search.NewRegistry()
 23→
 24→	for _, cc := range search.ContractCases() {
 25→		if cc.SkipExport {
 26→			continue
 27→		}
 28→
 29→		t.Run(cc.Name, func(t *testing.T) {
 30→			t.Parallel()
 31→
 32→			reg := defaultReg
 33→			if cc.Registry != nil {
 34→				reg = cc.Registry
 35→			}
 36→
 37→			h := handler.ExportCSV(nil, reg, search.MaxLimit)
 38→			u := buildExportURL(cc.Request)
 39→			w := httptest.NewRecorder()
 40→			r := httptest.NewRequest(http.MethodGet, u, nil)
 41→
 42→			if cc.Authenticated {
 43→				ctx := auth.SetClaims(r.Context(), &auth.Claims{})
 44→				r = r.WithContext(ctx)
 45→			}
 46→
 47→			if cc.WantValid {
 48→				// Validation passes → handler proceeds to DB call → nil pool panics.
 49→				// A panic (or non-400 response) means validation succeeded.
 50→				defer func() {
 51→					if rec := recover(); rec == nil {
 52→						if w.Code == http.StatusBadRequest {
 53→							t.Fatalf("expected validation to pass, got 400: %s", w.Body.String())
 54→						}
 55→					}
 56→					// Panic from nil pool = validation passed ✓
 57→				}()
 58→				h(w, r)
 59→				return
 60→			}
 61→
 62→			// Expect validation failure → HTTP 400.
 63→			h(w, r)
 64→
 65→			if w.Code != http.StatusBadRequest {
 66→				t.Fatalf("HTTP status: got %d, want %d; body: %s",
 67→					w.Code, http.StatusBadRequest, w.Body.String())
 68→			}
 69→
 70→			var body struct {
 71→				Errors []struct {
 72→					Field   string `json:"field"`
 73→					Message string `json:"message"`
 74→				} `json:"errors"`
 75→			}
 76→			if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
 77→				t.Fatalf("decode body: %v", err)
 78→			}
 79→			if len(body.Errors) == 0 {
 80→				t.Fatal("expected validation errors in response body")
 81→			}
 82→
 83→			found := false
 84→			for _, e := range body.Errors {
 85→				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
 86→					found = true
 87→					break
 88→				}
 89→			}
 90→			if !found {
 91→				t.Errorf("expected error field=%q containing %q, got: %+v",
 92→					cc.WantField, cc.WantContains, body.Errors)
 93→			}
 94→		})
 95→	}
 96→}
